UPDATE public.panduan_content SET steps = $panduan$[{"image": "/panduan/school-dashboard.jpg", "title": "1. Dashboard Utama", "bullets": ["Banner biru atas: persentase kehadiran + tombol shortcut Scan Absensi.", "Kartu statistik: Total Kelas, Siswa Terdaftar, Hadir Hari Ini, Belum/Alfa.", "Grafik harian / mingguan / bulanan untuk analisa kehadiran.", "Widget 'Sedang Berlangsung' menampilkan jadwal kelas live.", "Pengumuman Sekolah aktif tampil otomatis di bawah."], "description": "Setelah login, Anda akan masuk ke Dashboard Sekolah. Halaman ini menampilkan ringkasan kehadiran hari ini, total siswa, kelas, dan jadwal live. Cocok sebagai control panel harian."}, {"image": "/panduan/school-monitoring.jpg", "title": "2. Monitoring Real-time", "bullets": ["Status: Hadir, Izin, Sakit, Alfa, Belum (status netral untuk yang belum absen).", "Progress bar kehadiran realtime per kelas.", "Live Feed siswa yang datang dan pulang dengan jam tepat.", "Filter per kelas untuk fokus pengawasan.", "Tombol 'Live Monitor Publik' membuka tampilan TV tanpa login."], "description": "Menu Monitoring menampilkan absensi yang masuk secara real-time. Cocok ditampilkan di TV sekolah lewat tombol 'Live Monitor Publik'."}, {"image": "/panduan/public-monitor-datang.jpg", "title": "2b. Live Monitor Publik (Datang & Pulang)", "bullets": ["Akses link Live Monitor langsung dari menu Monitoring \u2192 tombol 'Live Monitor Publik'.", "Tersedia 2 mode: Monitor Kedatangan & Monitor Kepulangan.", "Counter besar: Total, Hadir, Izin, Sakit, Alfa, Belum.", "Auto-refresh setiap 5 detik \u2014 tidak perlu reload manual.", "Tombol Fullscreen untuk tampilan TV."], "description": "Tampilan layar publik yang bisa diakses tanpa login \u2014 cocok ditampilkan di TV gerbang sekolah. Tersedia 2 mode: monitor Kedatangan (status Hadir/Izin/Sakit/Alfa/Belum) dan monitor Kepulangan (siapa yang sudah pulang per kelas)."}, {"image": "/panduan/public-monitor-pulang.jpg", "title": "2c. Monitor Kepulangan per Kelas", "bullets": ["Tab horizontal per kelas \u2014 geser untuk pilih kelas.", "Kartu siswa dengan foto + status 'Menunggu' / 'Sudah Pulang'.", "Auto-rotate antar kelas tiap 8 detik (bisa di-pause).", "Progress bar kepulangan per kelas."], "description": "Halaman publik khusus pemantauan kepulangan siswa dikelompokkan per kelas dengan progress bar real-time."}, {"image": "/panduan/school-scan.jpg", "title": "3. Scan Absensi", "bullets": ["Klik 'Aktifkan Kamera' lalu arahkan ke QR Code siswa.", "Mode QR/Barcode auto-confirm setelah 3 detik deteksi stabil.", "Mode Face Recognition: interval 10 detik per wajah.", "Input NIS Manual untuk fallback jika kamera tidak tersedia.", "Suara konfirmasi (TTS) otomatis menyebut nama siswa."], "description": "Buka menu Scan Absensi untuk melakukan absensi via Barcode/QR atau Face Recognition. Bisa juga input NIS manual jika kamera bermasalah."}, {"image": "/panduan/school-classes.jpg", "title": "4. Kelola Kelas", "bullets": ["Klik 'Tambah Kelas' untuk membuat kelas baru.", "Edit nama kelas \u2014 sinkron otomatis ke siswa & wali kelas.", "Klik kartu kelas untuk lihat detail siswa dan absensi hari ini.", "Kapasitas kelas mengikuti tier subscription Anda."], "description": "Menu Kelas digunakan untuk membuat dan mengatur daftar kelas. Tiap kelas otomatis menampilkan rekap absensi harian dan total siswa."}, {"image": "/panduan/school-students.jpg", "title": "5. Data Siswa", "bullets": ["Tombol 'Tambah Siswa' untuk input manual satu per satu.", "Tombol 'Import' untuk upload Excel massal (template tersedia).", "'Naik Kelas' untuk pindahkan siswa antar kelas (single/bulk).", "'Download QR' untuk cetak kartu QR siswa per kelas.", "Klik nama siswa untuk lihat detail kehadiran lengkap."], "description": "Kelola data siswa termasuk QR Code, foto wajah untuk Face Recognition, NIS, gender, dan kontak wali murid."}, {"image": "/panduan/school-identitas-barcode.jpg", "title": "5b. Identitas & Barcode Per Siswa", "bullets": ["Header profil: Foto, Nama, Kelas, NIS, dan status absensi hari ini.", "Kartu statistik 4 kolom: total Hadir, Izin, Sakit, dan Alfa.", "Panel 'Identitas Lengkap': Nama, Kelas, NIS, Tanggal Terdaftar.", "Panel 'Data Wali / Orang Tua': Nama Wali & No. HP Wali.", "Panel 'Barcode Siswa': QR Code unik per siswa + tombol 'Download QR Code'.", "Tombol pensil di header untuk edit data siswa langsung dari halaman ini."], "description": "Klik nama siswa pada halaman Data Siswa untuk membuka halaman detail Identitas Lengkap & Barcode Siswa."}, {"image": "/panduan/school-announcements.jpg", "title": "6. Pengumuman Sekolah", "bullets": ["Klik 'Buat Baru' untuk membuat pengumuman dengan rich text editor.", "Atur target: Staf, Guru, atau Wali Kelas (multi-select).", "Tandai pengumuman penting agar tampil di top dashboard.", "Pengumuman dikirim juga sebagai notifikasi in-app."], "description": "Kirim pengumuman ke seluruh staf, guru, dan wali kelas. Bisa diberi label Informasi, Penting, atau Mendesak."}, {"image": "/panduan/school-history.jpg", "title": "7. Laporan & Rekap (History)", "bullets": ["Pilih rentang tanggal: 30, 60, atau 90 hari.", "Tab 'Rekap Kehadiran' (Datang) dan 'Rekap Kepulangan' terpisah.", "Filter per kelas untuk drill-down detail.", "Klik 'Export Excel' untuk unduh laporan lengkap dengan tanda tangan.", "Status Datang & Pulang dipisah ketat \u2014 tidak tercampur."], "description": "Menu History menampilkan analitik dan rekap kehadiran lengkap. Bisa export ke Excel format siap laporan."}, {"image": "/panduan/school-attendance-table.jpg", "title": "8. Riwayat Absensi (Tabel per Kelas)", "bullets": ["Pilih tab Kehadiran (Datang) atau Kepulangan (Pulang).", "Filter berdasarkan tanggal, kelas, dan nama/NIS siswa.", "Klik kartu kelas untuk membuka tabel detail siswa.", "Ubah status manual: H (Hadir), I (Izin), S (Sakit), A (Alfa).", "Cocok untuk koreksi data absensi yang terlewat atau salah."], "description": "Halaman Riwayat Absensi memudahkan Anda mengoreksi atau melengkapi data absensi harian dalam bentuk tabel per kelas."}, {"image": "/panduan/school-staff.jpg", "title": "9. Guru & Staff", "bullets": ["Kelola akun Guru, Operator, dan Bendahara dalam satu halaman.", "Statistik atas: Total Akun, Guru, Operator, Bendahara.", "Tombol Tambah Akun untuk menambah staff baru, atau Import Excel untuk batch.", "Setiap kartu menampilkan hak akses (icon) dan status absensi hari ini.", "Cetak QR/Barcode untuk absensi staff lewat tombol QR pada kartu."], "description": "Halaman Guru & Staff adalah pusat kelola akun internal sekolah \u2014 guru, operator, dan bendahara \u2014 beserta hak aksesnya."}, {"image": "/panduan/school-settings.jpg", "title": "10. Pengaturan Sekolah", "bullets": ["Logo sekolah otomatis sinkron ke sidebar, kartu ID, dan notifikasi WA.", "Zona waktu menentukan jam cut-off absensi.", "Atur jam masuk & jam pulang default untuk validasi otomatis."], "description": "Atur identitas sekolah (nama, NPSN, alamat, logo), zona waktu (WIB/WITA/WIT), dan jam absensi default."}]$panduan$::jsonb WHERE role_id='school';